query:
UPDATE articles SET 
  title = TRIM(REGEXP_REPLACE(
    REGEXP_REPLACE(
      REGEXP_REPLACE(
        REGEXP_REPLACE(
          REGEXP_REPLACE(title, ' - Top Picks & Reviews', ''),
          ' - Top Pi Products', ''
        ),
        ' - - - - - ', ''
      ),
      ' - - - - ', ''
    ),
    ' - - - ', ''
  ))
WHERE title LIKE '%Top Picks%' OR title LIKE '% - - %';

